SELECT area_name, population, area_size
FROM nonmetropolitan_areas
WHERE state = 'Hawaii';

SELECT area_name, population
FROM nonmetropolitan_areas
ORDER BY population DESC;

SELECT SUM(population) AS total_population
     FROM nonmetropolitan_areas
     WHERE state = 'Hawaii';

SELECT area_name
FROM nonmetropolitan_areas
WHERE population = (SELECT MAX(population) FROM nonmetropolitan_areas);

SELECT AVG(annual_mean_wage) AS average_wage
FROM wage_data
WHERE year = 2023;

SELECT AVG(annual_mean_wage) AS avg_annual_wage
FROM wage_data
WHERE year = 2023 AND occupation_id = 0;
